questionvariables.text:
/* 1. Linear Scale Factor (k) */
/* Enlarging from a prototype to a real industrial tank */
k: 5 + rand(6);           /* Scale factor k between 5 and 10 */

/* 2. Prototype (Object) Dimensions */
r_p: rand(2)+2;                   /* Radius in meters */
h_p: (2)+6;                   /* Cylindrical height in meters */

/* 3. Calculations for Prototype (The Object) */
area_base_p: %pi * r_p^2;
area_curved_p: (2 * %pi * r_p * h_p) + (2 * %pi * r_p^2); /* Cyl side + Hemi surface */
vol_p: (%pi * r_p^2 * h_p) + (2/3 * %pi * r_p^3);

/* 4. Calculations for Industrial Tank (The Image) */
/* Linear Dimensions */
r_i: r_p * k;
h_i: h_p * k;

/* Area and Volume Scale Factors */
asf: k^2;
vsf: k^3;

/* Values for the Industrial Tank */
total_area_i: float(area_curved_p * asf);
total_vol_i: float(vol_p * vsf);

/* 5. Teacher Answers */
ta1: k;               /* Linear Scale Factor */
ta2: asf;             /* Area Scale Factor */
ta3: vsf;             /* Volume Scale Factor */
ta4: decimalplaces(total_vol_i,2);     /* Final enlarged volume */
